      { word: "fiscal",      pron: "/ˈfɪskəl/",        pos: "adj.",    meanings: ["재정의", "회계의"],              example: "The fiscal year's environmental spending was higher than in any previous period.",        exampleKr: "회계 연도의 환경 지출이 이전 어느 기간보다 높았다." },
      { word: "invoice",     pron: "/ˈɪnvɔɪs/",       pos: "n.",      meanings: ["청구서", "송장"],                example: "The contractor sent an invoice for the solar panel installation work completed.",        exampleKr: "계약자가 완료된 태양광 패널 설치 작업에 대한 청구서를 보냈다." },
      { word: "liaison",     pron: "/liˈeɪzɒn/",       pos: "n.",      meanings: ["연락 담당자", "연결"],           example: "The company appointed a liaison to coordinate with national environmental regulators.",   exampleKr: "회사가 국가 환경 규제 기관과 조율하기 위해 연락 담당자를 임명했다." },
      { word: "lucrative",   pron: "/ˈluːkrətɪv/",    pos: "adj.",    meanings: ["수익성 있는", "돈이 되는"],      example: "Renewable energy has become a highly lucrative sector for international investors.",      exampleKr: "재생 에너지가 국제 투자자들에게 매우 수익성 있는 분야가 되었다." },
      { word: "merger",      pron: "/ˈmɜːrdʒər/",     pos: "n.",      meanings: ["합병"],                        example: "The merger of two clean energy firms created the largest solar installer in the region.", exampleKr: "두 청정 에너지 회사의 합병이 해당 지역에서 가장 큰 태양광 설치 업체를 만들었다." },
      { word: "procurement", pron: "/prəˈkjʊərmənt/", pos: "n.",      meanings: ["조달", "구매"],                  example: "Sustainable procurement policies require suppliers to meet environmental certification criteria.", exampleKr: "지속 가능한 조달 정책은 공급업체들이 환경 인증 기준을 충족할 것을 요구한다." },
      { word: "ratify",      pron: "/ˈrætɪfaɪ/",      pos: "v.",      meanings: ["비준하다", "승인하다"],          example: "All G20 nations agreed to ratify the updated global biodiversity framework.",             exampleKr: "G20 모든 국가가 업데이트된 전 세계 생물 다양성 프레임워크를 비준하는 데 동의했다." },
      { word: "reimburse",   pron: "/ˌriːɪmˈbɜːrs/",  pos: "v.",      meanings: ["상환하다", "변제하다"],          example: "The organization reimbursed scientists for all travel costs incurred during fieldwork.",   exampleKr: "기관이 현장 작업 중 발생한 모든 여행 비용을 과학자들에게 상환했다." },
      { word: "revenue",     pron: "/ˈrevənjuː/",     pos: "n.",      meanings: ["수익", "세입"],                  example: "Carbon tax revenue is being reinvested in public green transport infrastructure.",        exampleKr: "탄소세 수익이 공공 녹색 교통 인프라에 재투자되고 있다." },
      { word: "sanction",    pron: "/ˈsæŋkʃən/",      pos: "n./v.",   meanings: ["제재", "승인하다"],              example: "International sanctions were imposed on companies linked to illegal Amazon deforestation.", exampleKr: "아마존 불법 삼림 벌채와 연관된 기업들에 국제적 제재가 부과되었다." },
      { word: "subsidiary",  pron: "/səbˈsɪdiəri/",   pos: "n.",      meanings: ["자회사", "보조의"],              example: "The firm's overseas subsidiary handles all environmental monitoring across the region.",   exampleKr: "회사의 해외 자회사가 해당 지역 전반의 모든 환경 모니터링을 처리한다." },
      { word: "turnover",    pron: "/ˈtɜːrnoʊvər/",   pos: "n.",      meanings: ["매출액", "이직률"],              example: "High staff turnover in conservation organizations weakens long-term program continuity.", exampleKr: "보전 기관의 높은 이직률이 장기 프로그램 연속성을 약화시킨다." },
      { word: "viable",      pron: "/ˈvaɪəbəl/",      pos: "adj.",    meanings: ["실행 가능한", "생존 가능한"],    example: "Solar plus battery storage is now a commercially viable alternative to diesel generators.", exampleKr: "태양광과 배터리 저장이 이제 디젤 발전기에 대한 상업적으로 실행 가능한 대안이다." },
      { word: "dividend",    pron: "/ˈdɪvɪdend/",     pos: "n.",      meanings: ["배당금", "이익"],                example: "Investing in nature-based solutions pays long-term dividends in ecosystem services.",     exampleKr: "자연 기반 해결책에 투자하는 것이 생태계 서비스에서 장기적인 이익을 가져온다." }
